add_action( 'wp_footer', 'social_icons_sprite', 1 );


function lbv_social_icon( $name ) {
    static $allowed = [
        'instagram', 'tiktok', 'youtube', 'facebook', 'x',
        'threads', 'reddit', 'weibo', 'spotify', 'domain', 'telegram'
    ];

    if ( ! in_array( $name, $allowed, true ) ) return '';

    return '<span class="lbv-icon icon-' . esc_attr( $name ) . '">'
        .     '<svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">'
        .         '<use href="#social-icon-' . esc_attr( $name ) . '"></use>'
        .     '</svg>'
        . '</span>';
}
